    78→
    79→/**
    80→ * Notes Store State
    81→ */
    82→interface NotesStore {
    83→  // State
    84→  notes: Record<string, Note>; // Map of note ID -> Note
    85→  activeNoteId: string | null; // Currently open note
    86→  sortConfig: NoteSortConfig;
    87→  filter: NoteFilter;
    88→
    89→  // Actions - CRUD
    90→  createNote: (params?: Partial<Note>) => Note;
    91→  getNote: (id: string) => Note | undefined;
    92→  updateNote: (id: string, updates: NoteUpdate) => void;
    93→  deleteNote: (id: string) => void;
    94→  duplicateNote: (id: string) => Note | null;
    95→
    96→  // Actions - Bulk operations
    97→  deleteNotes: (ids: string[]) => void;
    98→  moveNotesToFolder: (noteIds: string[], folderId: string | null) => void;
    99→  archiveNotes: (noteIds: string[]) => void;
   100→  unarchiveNotes: (noteIds: string[]) => void;
   101→
   102→  // Actions - Queries
   103→  getAllNotes: () => Note[];
   104→  getNotesByFolder: (folderId: string | null) => Note[];
   105→  getNotesBy: (predicate: (note: Note) => boolean) => Note[];
   106→  searchNotes: (query: string) => Note[];
   107→
   108→  // Actions - Pin/Archive/Favorite
   109→  togglePin: (id: string) => void;
   110→  toggleArchive: (id: string) => void;
   111→  toggleFavorite: (id: string) => void;
   112→
   113→  // Actions - Tags
   114→  addTag: (id: string, tag: string) => void;
   115→  removeTag: (id: string, tag: string) => void;
   116→  getAllTags: () => string[];
   117→  renameTagGlobally: (oldTag: string, newTag: string) => void;
   118→  deleteTagGlobally: (tag: string) => void;
   119→
   120→  // Actions - UI state
   121→  setActiveNote: (id: string | null) => void;
   122→  setSortConfig: (config: NoteSortConfig) => void;
   123→  setFilter: (filter: NoteFilter) => void;
   124→
   125→  // Actions - Utility
   126→  getNoteCount: () => number;
   127→  getNotesInFolder: (folderId: string | null) => Note[];
   128→  exportNotes: () => Note[];
   129→  importNotes: (notes: Note[], merge: boolean) => void;
   130→  clearAllNotes: () => void;
   131→
   132→  // Actions - Backlinks (Phase 4)
   133→  getBacklinks: (noteId: string) => Note[];
   134→  updateLinkedNotes: (noteId: string, content: string) => void;
   135→
   136→  // Actions - Templates (Phase 4)
   137→  getNoteTemplates: () => NoteTemplate[];
   138→  createNoteFromTemplate: (templateId: string) => Note | null;
   139→
   140→  // Actions - Daily Notes
   141→  getDailyNote: (date: Date) => Note | null;
   142→  createDailyNote: (date: Date) => Note;
   143→  getOrCreateDailyNote: (date: Date) => Note;
   144→}
   145→
   146→/**
   147→ * Default note values
   148→ */
   149→const createDefaultNote = (overrides?: Partial<Note>): Note => {
   150→  const now = new Date();
   151→  return {
   152→    id: uuidv4(),
   153→    folderId: null,
   154→    title: NOTE_CONSTANTS.DEFAULT_TITLE,
   155→    content: '', // Empty Lexical state
   156→    contentText: '',
   157→    tags: [],
   158→    createdAt: now,
   159→    updatedAt: now,
   160→    isPinned: false,
   161→    isArchived: false,
   162→    ...overrides,
   163→  };
   164→};
   165→
   166→/**
   167→ * Sort notes based on sort config
   168→ */
   169→const sortNotes = (notes: Note[], config: NoteSortConfig): Note[] => {
   170→  const sorted = [...notes];
   171→
   172→  sorted.sort((a, b) => {
   173→    let comparison = 0;
   174→
   175→    switch (config.field) {
   176→      case 'title':
   177→        comparison = a.title.localeCompare(b.title);
   178→        break;
   179→      case 'createdAt':
   180→        comparison = a.createdAt.getTime() - b.createdAt.getTime();
   181→        break;
   182→      case 'updatedAt':
   183→        comparison = a.updatedAt.getTime() - b.updatedAt.getTime();
   184→        break;
   185→      case 'manual':
   186→        // Manual sort - preserve order (could add sortOrder field in future)
   187→        comparison = 0;
   188→        break;
   189→    }
   190→
   191→    return config.order === 'asc' ? comparison : -comparison;
   192→  });
   193→
   194→  // Always pin pinned notes to top
   195→  return sorted.sort((a, b) => {
   196→    if (a.isPinned && !b.isPinned) return -1;
   197→    if (!a.isPinned && b.isPinned) return 1;
   198→    return 0;
   199→  });
   200→};
   201→
   202→/**
   203→ * Filter notes based on filter type
   204→ */
   205→const filterNotes = (notes: Note[], filter: NoteFilter): Note[] => {
   206→  switch (filter) {
   207→    case 'favorites':
   208→      return notes.filter((note) => note.isFavorite);
   209→    case 'pinned':
   210→      return notes.filter((note) => note.isPinned);
   211→    case 'archived':
   212→      return notes.filter((note) => note.isArchived);
   213→    case 'unarchived':
   214→      return notes.filter((note) => !note.isArchived);
   215→    case 'all':
   216→    default:
   217→      return notes;
   218→  }
   219→};
   220→
   221→/**
   222→ * Create the Notes store
   223→ */
   224→export const useNotesStore = create<NotesStore>()(
   225→  persist(
   226→    (set, get) => ({
   227→      // Initial state
   228→      notes: {},
   229→      activeNoteId: null,
   230→      sortConfig: {
   231→        field: 'updatedAt',
   232→        order: 'desc',
   233→      },
   234→      filter: 'unarchived',
   235→
   236→      // CRUD Operations
   237→      createNote: (params) => {
   238→        const newNote = createDefaultNote(params);
   239→        set((state) => ({
   240→          notes: {
   241→            ...state.notes,
   242→            [newNote.id]: newNote,
   243→          },
   244→          activeNoteId: newNote.id, // Auto-select new note
   245→        }));
   246→        log.debug('Note created', { id: newNote.id });
   247→        return newNote;
   248→      },
   249→
   250→      getNote: (id) => {
   251→        return get().notes[id];
   252→      },
   253→
   254→      updateNote: (id, updates) => {
   255→        const note = get().notes[id];
   256→        if (!note) {
   257→          log.warn('Note not found', { id });
   258→          return;
   259→        }
   260→
   261→        // Only update timestamp if content/title/tags actually changed
   262→        // Skip timestamp update for UI-only changes (like folderId without content change)
   263→        const shouldUpdateTimestamp =
   264→          updates.content !== undefined ||
   265→          updates.title !== undefined ||
   266→          updates.tags !== undefined;
   267→
   268→        set((state) => ({
   269→          notes: {
   270→            ...state.notes,
   271→            [id]: {
   272→              ...note,
   273→              ...updates,
   274→              ...(shouldUpdateTimestamp ? { updatedAt: new Date() } : {}),
   275→            },
   276→          },
   277→        }));
   278→        log.debug('Note updated', { id, timestampUpdated: shouldUpdateTimestamp });
   279→      },
   280→
   281→      deleteNote: (id) => {
   282→        // Save note for undo
   283→        const noteToDelete = get().notes[id];
   284→        if (!noteToDelete) {
   285→          log.warn('Note not found', { id });
   286→          return;
   287→        }
   288→
   289→        // Store the previous activeNoteId for undo
   290→        const wasActive = get().activeNoteId === id;
   291→
   292→        // Delete the note
   293→        set((state) => {
   294→          const { [id]: deleted, ...remainingNotes } = state.notes;
   295→          return {
   296→            notes: remainingNotes,
   297→            activeNoteId: state.activeNoteId === id ? null : state.activeNoteId,
   298→          };
   299→        });
   300→
   301→        log.debug('Note deleted', { id });
   302→
   303→        // Delete associated images from IndexedDB (async, fire-and-forget)
   304→        import('../services/indexedDB').then(({ indexedDBService }) => {
   305→          indexedDBService.deleteNoteImages(id).catch((err) => {
   306→            log.error('Failed to delete note images', { id, error: err });
   307→          });
   308→        });
   309→
   310→        // Add undo action
   311→        useUndoStore.getState().addUndoAction(
   312→          `Note "${noteToDelete.title}" deleted`,
   313→          () => {
   314→            // Restore the note
   315→            set((state) => ({
   316→              notes: {
   317→                ...state.notes,
   318→                [id]: noteToDelete,
   319→              },
   320→              activeNoteId: wasActive ? id : state.activeNoteId,
   321→            }));
   322→            log.debug('Note restored (undo)', { id });
   323→          }
   324→        );
   325→      },
   326→
   327→      duplicateNote: (id) => {
   328→        const original = get().notes[id];
   329→        if (!original) {
   330→          log.warn('Note not found', { id });
   331→          return null;
   332→        }
   333→
   334→        const duplicate = createDefaultNote({
   335→          ...original,
   336→          title: `${original.title} (Copy)`,
   337→          isPinned: false, // Don't copy pin status
   338→        });
   339→
   340→        set((state) => ({
   341→          notes: {
   342→            ...state.notes,
   343→            [duplicate.id]: duplicate,
   344→          },
   345→        }));
   346→
   347→        log.debug('Note duplicated', { original: id, duplicate: duplicate.id });
   348→        return duplicate;
   349→      },
   350→
   351→      // Bulk operations
   352→      deleteNotes: (ids) => {
   353→        set((state) => {
   354→          const remainingNotes = { ...state.notes };
   355→          ids.forEach((id) => delete remainingNotes[id]);
   356→          return {
   357→            notes: remainingNotes,
   358→            activeNoteId: ids.includes(state.activeNoteId || '')
   359→              ? null
   360→              : state.activeNoteId,
   361→          };
   362→        });
   363→        log.debug('Deleted notes', { count: ids.length });
   364→
   365→        // Delete associated images from IndexedDB (async, fire-and-forget)
   366→        import('../services/indexedDB').then(({ indexedDBService }) => {
   367→          ids.forEach((id) => {
   368→            indexedDBService.deleteNoteImages(id).catch((err) => {
   369→              log.error('Failed to delete images for note', { id, error: err });
   370→            });
   371→          });
   372→        });
   373→      },
   374→
   375→      moveNotesToFolder: (noteIds, folderId) => {
   376→        set((state) => {
   377→          const updatedNotes = { ...state.notes };
   378→          noteIds.forEach((id) => {
   379→            if (updatedNotes[id]) {
   380→              updatedNotes[id] = {
   381→                ...updatedNotes[id],
   382→                folderId,
   383→                updatedAt: new Date(),
   384→              };
   385→            }
   386→          });
   387→          return { notes: updatedNotes };
   388→        });
   389→        log.debug('Moved notes to folder', { count: noteIds.length, folderId });
   390→      },
   391→
   392→      archiveNotes: (noteIds) => {
   393→        set((state) => {
   394→          const updatedNotes = { ...state.notes };
   395→          noteIds.forEach((id) => {
   396→            if (updatedNotes[id]) {
   397→              updatedNotes[id] = {
   398→                ...updatedNotes[id],
   399→                isArchived: true,
   400→                updatedAt: new Date(),
   401→              };
   402→            }
   403→          });
   404→          return { notes: updatedNotes };
   405→        });
   406→        log.debug('Archived notes', { count: noteIds.length });
   407→      },
   408→
   409→      unarchiveNotes: (noteIds) => {
   410→        set((state) => {
   411→          const updatedNotes = { ...state.notes };
   412→          noteIds.forEach((id) => {
   413→            if (updatedNotes[id]) {
   414→              updatedNotes[id] = {
   415→                ...updatedNotes[id],
   416→                isArchived: false,
   417→                updatedAt: new Date(),
   418→              };
   419→            }
   420→          });
   421→          return { notes: updatedNotes };
   422→        });
   423→        log.debug('Unarchived notes', { count: noteIds.length });
   424→      },
   425→
   426→      // Queries
   427→      getAllNotes: () => {
   428→        const state = get();
   429→        const notes = Object.values(state.notes);
   430→        const filtered = filterNotes(notes, state.filter);
   431→        return sortNotes(filtered, state.sortConfig);
   432→      },
   433→
   434→      getNotesByFolder: (folderId) => {
   435→        const state = get();
   436→        const notes = Object.values(state.notes).filter(
   437→          (note) => note.folderId === folderId
   438→        );
   439→        const filtered = filterNotes(notes, state.filter);
   440→        return sortNotes(filtered, state.sortConfig);
   441→      },
   442→
   443→      getNotesBy: (predicate) => {
   444→        const notes = Object.values(get().notes).filter(predicate);
   445→        return sortNotes(notes, get().sortConfig);
   446→      },
   447→
   448→      searchNotes: (query) => {
   449→        if (!query.trim()) return [];
   450→
   451→        const lowerQuery = query.toLowerCase();
   452→        const notes = Object.values(get().notes).filter((note) => {
   453→          // Search in title, content text, and tags
   454→          return (
   455→            note.title.toLowerCase().includes(lowerQuery) ||
   456→            note.contentText.toLowerCase().includes(lowerQuery) ||
   457→            note.tags.some((tag) => tag.toLowerCase().includes(lowerQuery))
   458→          );
   459→        });
   460→
   461→        return sortNotes(notes, get().sortConfig);
   462→      },
   463→
   464→      // Pin/Archive
   465→      togglePin: (id) => {
   466→        const note = get().notes[id];
   467→        if (!note) return;
   468→
   469→        set((state) => ({
   470→          notes: {
   471→            ...state.notes,
   472→            [id]: {
   473→              ...note,
   474→              isPinned: !note.isPinned,
   475→              updatedAt: new Date(),
   476→            },
   477→          },
   478→        }));
   479→        log.debug('Toggled pin', { id, isPinned: !note.isPinned });
   480→      },
   481→
   482→      toggleArchive: (id) => {
   483→        const note = get().notes[id];
   484→        if (!note) return;
   485→
   486→        set((state) => ({
   487→          notes: {
   488→            ...state.notes,
   489→            [id]: {
   490→              ...note,
   491→              isArchived: !note.isArchived,
   492→              updatedAt: new Date(),
   493→            },
   494→          },
   495→        }));
   496→        log.debug('Toggled archive', { id, isArchived: !note.isArchived });
   497→      },
   498→
   499→      toggleFavorite: (id) => {
   500→        const note = get().notes[id];
   501→        if (!note) return;
   502→
   503→        set((state) => ({
   504→          notes: {
   505→            ...state.notes,
   506→            [id]: {
   507→              ...note,
   508→              isFavorite: !note.isFavorite,
   509→              updatedAt: new Date(),
   510→            },
   511→          },
   512→        }));
   513→        log.debug('Toggled favorite', { id, isFavorite: !note.isFavorite });
   514→      },
   515→
   516→      // Tags
   517→      addTag: (id, tag) => {
   518→        const note = get().notes[id];
   519→        if (!note) return;
   520→
   521→        // Don't add duplicate tags
   522→        if (note.tags.includes(tag)) return;
   523→
   524→        // Check max tags limit
   525→        if (note.tags.length >= NOTE_CONSTANTS.MAX_TAGS) {
   526→          log.warn('Max tags reached', { max: NOTE_CONSTANTS.MAX_TAGS });
   527→          return;
   528→        }
   529→
   530→        set((state) => ({
   531→          notes: {
   532→            ...state.notes,
   533→            [id]: {
   534→              ...note,
   535→              tags: [...note.tags, tag],
   536→              updatedAt: new Date(),
   537→            },
   538→          },
   539→        }));
   540→        log.debug('Added tag', { id, tag });
   541→      },
   542→
   543→      removeTag: (id, tag) => {
   544→        const note = get().notes[id];
   545→        if (!note) return;
   546→
   547→        set((state) => ({
   548→          notes: {
   549→            ...state.notes,
   550→            [id]: {
   551→              ...note,
   552→              tags: note.tags.filter((t) => t !== tag),
   553→              updatedAt: new Date(),
   554→            },
   555→          },
   556→        }));
   557→        log.debug('Removed tag', { id, tag });
   558→      },
   559→
   560→      getAllTags: () => {
   561→        const notes = Object.values(get().notes);
   562→        const tagSet = new Set<string>();
   563→        notes.forEach((note) => {
   564→          note.tags.forEach((tag) => tagSet.add(tag));
   565→        });
   566→        return Array.from(tagSet).sort();
   567→      },
   568→
   569→      renameTagGlobally: (oldTag, newTag) => {
   570→        const notes = get().notes;
   571→        const updatedNotes: Record<string, Note> = {};
   572→
   573→        Object.entries(notes).forEach(([id, note]) => {
   574→          if (note.tags.includes(oldTag)) {
   575→            updatedNotes[id] = {
   576→              ...note,
   577→              tags: note.tags.map((tag) => (tag === oldTag ? newTag : tag)),
   578→              updatedAt: new Date(),
   579→            };
   580→          }
   581→        });
   582→
   583→        if (Object.keys(updatedNotes).length > 0) {
   584→          set((state) => ({
   585→            notes: {
   586→              ...state.notes,
   587→              ...updatedNotes,
   588→            },
   589→          }));
   590→          log.info('Tag renamed globally', { oldTag, newTag, count: Object.keys(updatedNotes).length });
   591→        }
   592→      },
   593→
   594→      deleteTagGlobally: (tag) => {
   595→        const notes = get().notes;
   596→        const updatedNotes: Record<string, Note> = {};
   597→
   598→        Object.entries(notes).forEach(([id, note]) => {
   599→          if (note.tags.includes(tag)) {
   600→            updatedNotes[id] = {
   601→              ...note,
   602→              tags: note.tags.filter((t) => t !== tag),
   603→              updatedAt: new Date(),
   604→            };
   605→          }
   606→        });
   607→
   608→        if (Object.keys(updatedNotes).length > 0) {
   609→          set((state) => ({
   610→            notes: {
   611→              ...state.notes,
   612→              ...updatedNotes,
   613→            },
   614→          }));
   615→          log.info('Tag deleted globally', { tag, count: Object.keys(updatedNotes).length });
   616→        }
   617→      },
   618→
   619→      // UI state
   620→      setActiveNote: (id) => {
   621→        set({ activeNoteId: id });
   622→        log.debug('Active note set', { id });
   623→      },
   624→
   625→      setSortConfig: (config) => {
   626→        set({ sortConfig: config });
   627→        log.debug('Sort config updated', { config });
   628→      },
   629→
   630→      setFilter: (filter) => {
   631→        set({ filter });
   632→        log.debug('Filter updated', { filter });
   633→      },
   634→
   635→      // Utility
   636→      getNoteCount: () => {
   637→        return Object.keys(get().notes).length;
   638→      },
   639→
   640→      getNotesInFolder: (folderId) => {
   641→        return Object.values(get().notes).filter(
   642→          (note) => note.folderId === folderId
   643→        );
   644→      },
   645→
   646→      exportNotes: () => {
   647→        return Object.values(get().notes);
   648→      },
   649→
   650→      importNotes: (notes, merge) => {
   651→        if (!merge) {
   652→          // Replace all notes
   653→          set({
   654→            notes: Object.fromEntries(notes.map((note) => [note.id, note])),
   655→            activeNoteId: null,
   656→          });
   657→          log.info('Imported notes', { count: notes.length, mode: 'replace' });
   658→        } else {
   659→          // Merge with existing notes
   660→          set((state) => {
   661→            const updatedNotes = { ...state.notes };
   662→            notes.forEach((note) => {
   663→              updatedNotes[note.id] = note;
   664→            });
   665→            return { notes: updatedNotes };
   666→          });
   667→          log.info('Imported notes', { count: notes.length, mode: 'merge' });
   668→        }
   669→      },
   670→
   671→      clearAllNotes: () => {
   672→        set({ notes: {}, activeNoteId: null });
   673→        log.info('All notes cleared');
   674→      },
   675→
   676→      // ==================== BACKLINKS (Phase 4) ====================
   677→
   678→      getBacklinks: (noteId: string) => {
   679→        const state = get();
   680→        const note = state.notes[noteId];
   681→        if (!note) return [];
   682→
   683→        return getBacklinksUtil(noteId, note.title, state.notes);
   684→      },
   685→
   686→      updateLinkedNotes: (noteId: string, content: string) => {
   687→        const state = get();
   688→        const linkTitles = extractWikiLinks(content);
   689→        const linkedNoteIds = resolveLinksToIds(linkTitles, state.notes);
   690→
   691→        set((currentState) => {
   692→          const note = currentState.notes[noteId];
   693→          if (!note) return currentState;
   694→
   695→          return {
   696→            notes: {
   697→              ...currentState.notes,
   698→              [noteId]: {
   699→                ...note,
   700→                linkedNotes: linkedNoteIds,
   701→              },
   702→            },
   703→          };
   704→        });
   705→      },
   706→
   707→      // ==================== TEMPLATES (Phase 4) ====================
   708→
   709→      getNoteTemplates: () => {
   710→        return DEFAULT_NOTE_TEMPLATES;
   711→      },
   712→
   713→      createNoteFromTemplate: (templateId: string) => {
   714→        const template = DEFAULT_NOTE_TEMPLATES.find((t) => t.id === templateId);
   715→        if (!template) return null;
   716→
   717→        const newNote = createDefaultNote({
   718→          title: template.name,
   719→          contentText: template.description,
   720→          tags: template.defaultTags || [],
   721→          icon: template.icon,
   722→        });
   723→
   724→        set((state) => ({
   725→          notes: {
   726→            ...state.notes,
   727→            [newNote.id]: newNote,
   728→          },
   729→          activeNoteId: newNote.id,
   730→        }));
   731→
   732→        log.debug('Created note from template', { template: template.name });
   733→        return newNote;
   734→      },
   735→
   736→      // ==================== DAILY NOTES ====================
   737→
   738→      getDailyNote: (date: Date) => {
   739→        const state = get();
   740→        const settings = useSettingsStore.getState().dailyNotes;
   741→        return getDailyNoteUtil(date, state.notes, settings);
   742→      },
   743→
   744→      createDailyNote: (date: Date) => {
   745→        const settings = useSettingsStore.getState().dailyNotes;
   746→        const newNote = createDailyNoteUtil(date, settings);
   747→
   748→        set((state) => ({
   749→          notes: {
   750→            ...state.notes,
   751→            [newNote.id]: newNote,
   752→          },
   753→          activeNoteId: newNote.id,
   754→        }));
   755→
   756→        log.info('Created daily note', { date: newNote.title, id: newNote.id });
   757→        return newNote;
   758→      },
   759→
   760→      getOrCreateDailyNote: (date: Date) => {
   761→        const state = get();
   762→        const settings = useSettingsStore.getState().dailyNotes;
   763→
   764→        // Try to find existing note
   765→        const existingNote = getDailyNoteUtil(date, state.notes, settings);
   766→        if (existingNote) {
   767→          // Set as active note
   768→          set({ activeNoteId: existingNote.id });
   769→          log.debug('Found existing daily note', { date: existingNote.title });
   770→          return existingNote;
   771→        }
   772→
   773→        // Create new note
   774→        const newNote = createDailyNoteUtil(date, settings);
   775→        set((currentState) => ({
   776→          notes: {
   777→            ...currentState.notes,
   778→            [newNote.id]: newNote,
   779→          },
   780→          activeNoteId: newNote.id,
   781→        }));
   782→
   783→        log.info('Auto-created daily note', { date: newNote.title, id: newNote.id });
   784→        return newNote;
   785→      },
   786→    }),
   787→    {
   788→      name: 'notes', // IndexedDB key
   789→      storage: createJSONStorage(() => createSyncedStorage()),
   790→      partialize: (state) => ({
   791→        // Only persist notes, not UI state
   792→        notes: state.notes,
   793→      }),
   794→      // Handle date serialization
   795→      onRehydrateStorage: () => (state) => {
   796→        log.debug('Notes store rehydrating');
   797→        if (state) {
   798→          try {
   799→            // Ensure notes object exists and is valid
   800→            if (state.notes && typeof state.notes === 'object') {
   801→              // Convert date strings back to Date objects
   802→              Object.values(state.notes).forEach((note) => {
   803→                if (typeof note.createdAt === 'string') {
   804→                  note.createdAt = new Date(note.createdAt);
   805→                }
   806→                if (typeof note.updatedAt === 'string') {
   807→                  note.updatedAt = new Date(note.updatedAt);
   808→                }
   809→              });
   810→            } else {
   811→              log.warn('Corrupted notes data detected, resetting to empty');
   812→              state.notes = {};
   813→            }
   814→          } catch (err) {
   815→            log.error('Error during notes store rehydration', { error: err });
   816→            // Reset to safe defaults
   817→            state.notes = {};
   818→            state.activeNoteId = null;
   819→          }
   820→        }
   821→        log.info('Notes store rehydrated');
   822→      },
   823→    }
   824→  )
   825→);
   826→
   827→/**
   828→ * Selector hooks for optimized re-renders
   829→ */
   830→export const useActiveNote = () =>
   831→  useNotesStore((state) => {
   832→    const activeId = state.activeNoteId;
   833→    return activeId ? state.notes[activeId] : null;
   834→  });
   835→
   836→export const useNotesByFolder = (folderId: string | null) =>
   837→  useNotesStore((state) => state.getNotesByFolder(folderId));
   838→
   839→export const useAllTags = () => useNotesStore((state) => state.getAllTags());
   840→

