   397→          : anchorNode.getTopLevelElementOrThrow();
   398→
   399→        if ($isQuoteNode(element)) {
   400→          // If already a quote, convert to paragraph
   401→          const paragraph = $createParagraphNode();
   402→          element.replace(paragraph, true);
   403→        } else if (!$isListNode(element)) {
   404→          const quote = $createQuoteNode();
   405→          element.replace(quote, true);
   406→        }
   407→      }
   408→    });
   409→  };
   410→
   411→  const formatBulletList = () => {
   412→    editor.dispatchCommand(INSERT_UNORDERED_LIST_COMMAND, undefined);
   413→  };
   414→
   415→  const formatNumberedList = () => {
   416→    editor.dispatchCommand(INSERT_ORDERED_LIST_COMMAND, undefined);
   417→  };
   418→
   419→  const undo = () => {
   420→    editor.dispatchCommand(UNDO_COMMAND, undefined);
   421→  };
   422→
   423→  const redo = () => {
   424→    editor.dispatchCommand(REDO_COMMAND, undefined);
   425→  };
   426→
   427→  const handleImageUpload = async (event: React.ChangeEvent<HTMLInputElement>) => {
   428→    const file = event.target.files?.[0];
   429→    if (!file) return;
   430→
   431→    // Reset input immediately
   432→    if (fileInputRef.current) {
   433→      fileInputRef.current.value = '';
   434→    }
   435→
   436→    try {
   437→      // Store image in IndexedDB with compression
   438→      const imageId = await indexedDBService.storeImage(noteId, file);
   439→
   440→      // Retrieve compressed blob
   441→      const blob = await indexedDBService.getImage(imageId);
   442→      if (!blob) {
   443→        console.error('Failed to retrieve stored image');
   444→        return;
   445→      }
   446→
   447→      // Create blob URL for rendering
   448→      const blobUrl = URL.createObjectURL(blob);
   449→
   450→      // Insert image node into editor
   451→      editor.update(() => {
   452→        const selection = $getSelection();
   453→        if ($isRangeSelection(selection)) {
   454→          const imageNode = $createImageNode({
   455→            altText: file.name,
   456→            src: blobUrl,
   457→            imageId: imageId,
   458→          });
   459→          selection.insertNodes([imageNode]);
   460→        }
   461→      });
   462→
   463→      console.log(`✅ Image uploaded: ${imageId} (${file.name})`);
   464→    } catch (error) {
   465→      console.error('Failed to upload image:', error);
   466→      alert(`Failed to upload image: ${error instanceof Error ? error.message : 'Unknown error'}\n\nPlease check:\n• File size (max 5MB)\n• Storage quota (Settings > Storage)`);
   467→    }
   468→  };
   469→
   470→  const btnClass = "p-2 hover:bg-surface-light-elevated dark:hover:bg-neutral-800 rounded transition-all duration-standard text-text-light-primary dark:text-text-dark-primary";
   471→  const dividerClass = "w-px h-6 bg-border-light dark:bg-border-dark";
   472→
   473→  return (
   474→    <div className="border-b border-border-light dark:border-border-dark bg-surface-light dark:bg-surface-dark-elevated p-3 flex items-center gap-2 flex-wrap">
   475→      {/* Undo/Redo */}
   476→      <button onClick={undo} className={btnClass} title="Undo (Cmd+Z)">
   477→        ↶
   478→      </button>
   479→      <button onClick={redo} className={btnClass} title="Redo (Cmd+Shift+Z)">
   480→        ↷
   481→      </button>
   482→
   483→      <div className={dividerClass} />
   484→
   485→      {/* Text Format */}
   486→      <button onClick={() => formatText('bold')} className={btnClass} title="Bold (Cmd+B)">
   487→        <span className="font-bold">B</span>
   488→      </button>
   489→      <button onClick={() => formatText('italic')} className={btnClass} title="Italic (Cmd+I)">
   490→        <span className="italic">I</span>
   491→      </button>
   492→      <button onClick={() => formatText('underline')} className={btnClass} title="Underline (Cmd+U)">
   493→        <span className="underline">U</span>
   494→      </button>
   495→      <button onClick={() => formatText('strikethrough')} className={btnClass} title="Strikethrough">
   496→        <span className="line-through">S</span>
   497→      </button>
   498→      <button onClick={() => formatText('code')} className={btnClass} title="Code">
   499→        <span className="font-mono text-sm">&lt;/&gt;</span>
   500→      </button>
   501→
   502→      <div className={dividerClass} />
   503→
   504→      {/* Headings */}
   505→      <button onClick={() => formatHeading('h1')} className={btnClass} title="Heading 1">
   506→        <span className="font-bold text-lg">H1</span>
   507→      </button>
   508→      <button onClick={() => formatHeading('h2')} className={btnClass} title="Heading 2">
   509→        <span className="font-bold">H2</span>
   510→      </button>
   511→      <button onClick={() => formatHeading('h3')} className={btnClass} title="Heading 3">
   512→        <span className="font-bold text-sm">H3</span>
   513→      </button>
   514→      <button onClick={formatParagraph} className={btnClass} title="Paragraph">
   515→        <span className="text-sm">P</span>
   516→      </button>
   517→
   518→      <div className={dividerClass} />
   519→
   520→      {/* Lists */}
   521→      <button onClick={formatBulletList} className={btnClass} title="Bullet List">
   522→        ≡
   523→      </button>
   524→      <button onClick={formatNumberedList} className={btnClass} title="Numbered List">
   525→        ⋮
   526→      </button>
   527→      <button onClick={formatQuote} className={btnClass} title="Quote">
   528→        "
   529→      </button>
   530→
   531→      <div className={dividerClass} />
   532→
   533→      {/* Image Upload */}
   534→      <input
   535→        ref={fileInputRef}
   536→        type="file"
   537→        accept="image/*"
   538→        onChange={handleImageUpload}
   539→        className="hidden"
   540→      />
   541→      <button
   542→        onClick={() => fileInputRef.current?.click()}
   543→        className={btnClass}
   544→        title="Insert Image"
   545→      >
   546→        🖼️
   547→      </button>
