   554→      </span>
   555→    </div>
   556→  );
   557→};
   558→
   559→/**
   560→ * Auto-save Plugin
   561→ * Debounces editor changes and saves to store
   562→ */
   563→const AutoSavePlugin: React.FC<{ noteId: string }> = ({ noteId }) => {
   564→  const [isSaving, setIsSaving] = useState(false);
   565→  const updateNote = useNotesStore((state) => state.updateNote);
   566→
   567→  // Track timeout ID and last saved content to prevent redundant saves
   568→  const timeoutIdRef = useRef<ReturnType<typeof setTimeout> | null>(null);
   569→  const lastContentRef = useRef<string>('');
   570→  const lastTextRef = useRef<string>('');
   571→
   572→  const handleChange = useCallback((editorState: EditorState) => {
   573→    // Extract plain text for search
   574→    editorState.read(() => {
   575→      const root = $getRoot();
   576→      const contentText = root.getTextContent();
   577→      const contentJson = JSON.stringify(editorState.toJSON());
   578→
   579→      // Skip save if content hasn't actually changed
   580→      if (contentJson === lastContentRef.current && contentText === lastTextRef.current) {
   581→        return;
   582→      }
   583→
   584→      // Clear previous timeout to implement proper debouncing
   585→      if (timeoutIdRef.current) {
   586→        clearTimeout(timeoutIdRef.current);
   587→      }
   588→
   589→      // Debounced save with error handling
   590→      timeoutIdRef.current = setTimeout(() => {
   591→        setIsSaving(true);
   592→
   593→        try {
   594→          // Zustand is synchronous, but IndexedDB persistence could fail
   595→          updateNote(noteId, {
   596→            content: contentJson,
   597→            contentText,
   598→          });
   599→
   600→          // Update refs with saved content
   601→          lastContentRef.current = contentJson;
   602→          lastTextRef.current = contentText;
   603→
   604→          // Reset saving state after a brief delay
   605→          setTimeout(() => setIsSaving(false), 300);
   606→        } catch (error) {
   607→          console.error('❌ Failed to save note:', error);
   608→          setIsSaving(false);
   609→          // Error will be handled by IndexedDB quota monitoring system
   610→          // User will be alerted if quota is exceeded via Settings page
   611→        }
   612→      }, NOTE_CONSTANTS.AUTOSAVE_DEBOUNCE_MS);
   613→    });
   614→  }, [noteId, updateNote]);
   615→
   616→  // Cleanup timeout on unmount
   617→  useEffect(() => {
   618→    return () => {
   619→      if (timeoutIdRef.current) {
   620→        clearTimeout(timeoutIdRef.current);
   621→      }
   622→    };
   623→  }, []);
   624→
   625→  return (
   626→    <>
   627→      <OnChangePlugin onChange={handleChange} />
   628→      {isSaving && (
   629→        <div className="absolute top-2 right-2 text-xs text-text-light-secondary dark:text-text-dark-secondary">
   630→          Saving...
   631→        </div>
   632→      )}
   633→    </>
   634→  );
   635→};
   636→
   637→/**
