   639→ */
   640→const getEditorConfig = (initialContent?: string) => ({
   641→  namespace: 'NotesEditor',
   642→  editorState: initialContent || null,
   643→  theme: {
   644→    root: 'editor-root',
   645→    paragraph: 'editor-paragraph leading-relaxed', // 1.625 line-height for readability
   646→    text: {
   647→      bold: 'font-bold',
   648→      italic: 'italic',
   649→      underline: 'underline',
   650→      strikethrough: 'line-through',
   651→      code: 'font-mono bg-neutral-100 dark:bg-neutral-800 px-1.5 py-0.5 rounded text-sm',
   652→    },
   653→    heading: {
   654→      h1: 'text-4xl font-bold mt-8 mb-4 leading-tight tracking-tight',
   655→      h2: 'text-3xl font-bold mt-6 mb-3 leading-snug',
   656→      h3: 'text-2xl font-semibold mt-5 mb-2 leading-normal',
   657→    },
   658→    list: {
   659→      ul: 'list-disc list-inside my-4 space-y-1.5',
   660→      ol: 'list-decimal list-inside my-4 space-y-1.5',
   661→      listitem: 'my-1 leading-relaxed',
   662→    },
   663→    quote: 'border-l-4 border-accent-cyan dark:border-accent-magenta bg-surface-light-elevated dark:bg-surface-dark-elevated pl-4 py-3 italic my-4 rounded-r',
   664→    code: 'bg-neutral-900 dark:bg-neutral-950 text-neutral-100 p-4 rounded-lg font-mono text-sm my-4 overflow-x-auto shadow-sm',
   665→    link: 'text-accent-cyan dark:text-accent-magenta hover:underline transition-colors',
   666→  },
   667→  nodes: [
   668→    HeadingNode,
   669→    QuoteNode,
   670→    ListNode,
   671→    ListItemNode,
   672→    CodeNode,
   673→    CodeHighlightNode,
   674→    LinkNode,
   675→    AutoLinkNode,
   676→    TableNode,
   677→    TableCellNode,
   678→    TableRowNode,
   679→    ImageNode,
   680→  ],
   681→  onError: (error: Error) => {
   682→    console.error('Lexical error:', error);
   683→  },
   684→});
   685→
