/**
 * Word Count Plugin
 * Tracks word and character count from editor content
 */
const WordCountPlugin: React.FC<{ onUpdate: (words: number, chars: number) => void }> = ({ onUpdate }) => {
  const [editor] = useLexicalComposerContext();

  useEffect(() => {
