      if (!blob) {
        console.error('Failed to retrieve stored image');
        return;
      }

      // Create blob URL for rendering
      const blobUrl = URL.createObjectURL(blob);

      // Insert image node into editor
      editor.update(() => {
        const selection = $getSelection();
        if ($isRangeSelection(selection)) {
          const imageNode = $createImageNode({
            altText: file.name,
            src: blobUrl,
            imageId: imageId,
          });
          selection.insertNodes([imageNode]);
        }
      });

      console.log(`✅ Image uploaded: ${imageId} (${file.name})`);
    } catch (error) {
      console.error('Failed to upload image:', error);
      alert(`Failed to upload image: ${error instanceof Error ? error.message : 'Unknown error'}\n\nPlease check:\n• File size (max 5MB)\n• Storage quota (Settings > Storage)`);
    }
