  const btnClass = "p-2 hover:bg-surface-light-elevated dark:hover:bg-neutral-800 rounded transition-all duration-standard text-text-light-primary dark:text-text-dark-primary";
  const dividerClass = "w-px h-6 bg-border-light dark:bg-border-dark";

