      }

      const text = textNode.getTextContent();

      // Pattern to match [[Note Title]]
      const wikiLinkPattern = /\[\[([^\]]+)\]\]/g;
      let match;
      const matches: Array<{ start: number; end: number; title: string }> = [];

      while ((match = wikiLinkPattern.exec(text)) !== null) {
        matches.push({
          start: match.index,
          end: match.index + match[0].length,
          title: match[1].trim(),
        });
      }

      // If no matches, nothing to transform
      if (matches.length === 0) {
        return;
      }

      // Split text node into parts (text + WikiLinkNodes)
      let currentOffset = 0;
      const nodesToInsert: Array<TextNode | WikiLinkNode> = [];

      matches.forEach((linkMatch) => {
        // Add text before the link
        if (linkMatch.start > currentOffset) {
          const beforeText = text.slice(currentOffset, linkMatch.start);
          nodesToInsert.push(new TextNode(beforeText));
        }

        // Add WikiLinkNode
        const isBroken = isLinkBroken(linkMatch.title, notes);
        const wikiLinkNode = $createWikiLinkNode(linkMatch.title, isBroken);
        nodesToInsert.push(wikiLinkNode);

        currentOffset = linkMatch.end;
      });

      // Add remaining text after last link
      if (currentOffset < text.length) {
        const afterText = text.slice(currentOffset);
        nodesToInsert.push(new TextNode(afterText));
      }

      // Replace original text node with new nodes
      if (nodesToInsert.length > 0) {
        textNode.replace(nodesToInsert[0]);
        for (let i = 1; i < nodesToInsert.length; i++) {
          nodesToInsert[i - 1].insertAfter(nodesToInsert[i]);
        }
      }
    });

    return removeTransform;
  }, [editor, notes]);

  // Update WikiLinkNode broken states when notes change
  useEffect(() => {
    editor.update(() => {
      const root = $getRoot();

      // Find all WikiLinkNodes and update their broken state
      root.getChildren().forEach((node) => {
        node.getChildren().forEach((child) => {
          if ($isWikiLinkNode(child)) {
            const linkTitle = child.getLinkTitle();
            const isBroken = isLinkBroken(linkTitle, notes);

            // Update if state changed
            if (child.getIsBroken() !== isBroken) {
              child.setIsBroken(isBroken);
            }
          }
        });
      });
    });
  }, [editor, notes]);

  // Handle clicks on WikiLinkNodes
  useEffect(() => {
    const removeClickListener = editor.registerCommand(
      CLICK_COMMAND,
      (event: MouseEvent) => {
        const target = event.target as HTMLElement;

        // Check if clicked element is a wiki link
        if (target.classList.contains('wiki-link')) {
          event.preventDefault();

          // Get the clicked node
          editor.getEditorState().read(() => {
            const root = $getRoot();

            // Find WikiLinkNode that was clicked
            let clickedNode: WikiLinkNode | null = null;

            root.getChildren().forEach((node) => {
              node.getChildren().forEach((child) => {
                if ($isWikiLinkNode(child)) {
                  // Check if this is the clicked node by comparing DOM element
                  const dom = editor.getElementByKey(child.getKey());
                  if (dom === target) {
                    clickedNode = child;
                  }
                }
              });
            });

            if (clickedNode) {
              const linkTitle = clickedNode.getLinkTitle();
              const isBroken = clickedNode.getIsBroken();

              if (isBroken) {
                // Broken link - show create dialog
                setPendingLinkTitle(linkTitle);
                setCreateDialogOpen(true);
              } else {
                // Valid link - navigate to note
                const notesArray = Object.values(notes);
                const targetNote = notesArray.find(
                  (note) =>
                    note.title.toLowerCase() === linkTitle.toLowerCase() ||
                    note.title.toLowerCase().startsWith(linkTitle.toLowerCase())
                );

                if (targetNote) {
                  navigate(`/notes?note=${targetNote.id}`);
                }
              }
            }
          });

          return true; // Event handled
        }

        return false; // Event not handled
      },
      COMMAND_PRIORITY_LOW
    );

    return removeClickListener;
  }, [editor, notes, navigate]);

  // Handle create note confirmation
  const handleCreateNote = () => {
    if (!pendingLinkTitle) return;

    // Create new note with exact title
    const newNote = createNote({
      title: pendingLinkTitle,
      contentText: '',
      content: '',
    });

    // Navigate to new note
    navigate(`/notes?note=${newNote.id}`);

    // Close dialog
    setCreateDialogOpen(false);
    setPendingLinkTitle('');
  };

  return (
    <>
      {/* Create Note Confirmation Dialog */}
      <ConfirmDialog
        isOpen={createDialogOpen}
        onClose={() => {
          setCreateDialogOpen(false);
          setPendingLinkTitle('');
        }}
        onConfirm={handleCreateNote}
        title="Create Note"
        message={`Note "${pendingLinkTitle}" doesn't exist. Create it?`}
        confirmText="Create"
        cancelText="Cancel"
        variant="info"
      />
    </>
  );
}

